using Microsoft.ML;
using Microsoft.ML.Data;
using Microsoft.Extensions.ML;
using ChurnPredictor;

var builder = WebApplication.CreateBuilder(args);

// Train the model at startup and register the pooled prediction engine
var modelPath = TrainModel(builder.Environment.ContentRootPath);
builder.Services.AddPredictionEnginePool<CustomerData, ChurnPrediction>()
    .FromFile(modelPath);

var app = builder.Build();

app.MapGet("/", () => "Churn Predictor API — POST /predict with { age, income, region, purchaseHistory }");

app.MapPost("/predict", (PredictionEnginePool<CustomerData, ChurnPrediction> pool, CustomerRequest req) =>
{
    var input = new CustomerData
    {
        Age = req.Age,
        Income = req.Income,
        Region = req.Region,
        PurchaseHistory = req.PurchaseHistory
    };

    var prediction = pool.Predict(input);
    return Results.Ok(new
    {
        willChurn = prediction.PredictedLabel,
        probability = prediction.Probability,
        score = prediction.Score
    });
});

app.Run();

static string TrainModel(string contentRoot)
{
    var mlContext = new MLContext(seed: 42);

    var dataPath = Path.Combine(contentRoot, "Data", "customers.csv");
    var dataView = mlContext.Data.LoadFromTextFile<CustomerData>(
        dataPath, separatorChar: ',', hasHeader: true);

    var split = mlContext.Data.TrainTestSplit(dataView, testFraction: 0.2);

    var pipeline = mlContext.Transforms
        // Map "Yes"/"No" to boolean label
        .Conversion.MapValueToKey("Label", nameof(CustomerData.Churned))
        // One-hot encode the Region text column
        .Append(mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", nameof(CustomerData.Region)))
        // Combine all features
        .Append(mlContext.Transforms.Concatenate("Features",
            nameof(CustomerData.Age),
            nameof(CustomerData.Income),
            nameof(CustomerData.PurchaseHistory),
            "RegionEncoded"))
        .Append(mlContext.Transforms.NormalizeMinMax("Features"))
        // Binary classification trainer
        .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression(
            labelColumnName: "Label", featureColumnName: "Features"))
        // Map the key label back to the original bool
        .Append(mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

    var model = pipeline.Fit(split.TrainSet);

    // Evaluate on the held-out test set
    var predictions = model.Transform(split.TestSet);
    var metrics = mlContext.BinaryClassification.Evaluate(predictions, labelColumnName: "Label");
    Console.WriteLine($"[ML.NET] AUC: {metrics.AreaUnderRocCurve:F4}, F1: {metrics.F1Score:F4}, Accuracy: {metrics.Accuracy:F4}");

    // Save model
    var modelPath = Path.Combine(contentRoot, "Data", "churn-model.zip");
    mlContext.Model.Save(model, dataView.Schema, modelPath);
    Console.WriteLine($"[ML.NET] Model saved to {modelPath}");

    return modelPath;
}

